<?php
// SecureVault - Registration with XXE (Self-contained lab)
session_start();
$db = new mysqli('localhost','root','','KrazePlanetLabs_DB');
if ($db->connect_error) die('<h3 style="padding:32px;font-family:sans-serif;color:#c00">DB: '.htmlspecialchars($db->connect_error).'</h3>');
$db->query("CREATE TABLE IF NOT EXISTS lab1406_users(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(100)NOT NULL,email VARCHAR(255)NOT NULL UNIQUE,password VARCHAR(255)NOT NULL,plan VARCHAR(50)DEFAULT'Free',avatar VARCHAR(4)DEFAULT'U',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)");
$chk=$db->query("SELECT id FROM lab1406_users WHERE email='demo@securevault.io'");
if($chk&&$chk->num_rows===0){$h=password_hash('demo@123',PASSWORD_BCRYPT);$db->query("INSERT INTO lab1406_users(name,email,password,plan,avatar)VALUES('Demo User','demo@securevault.io','$h','Pro','DU')");}
function esc($s){return htmlspecialchars((string)$s,ENT_QUOTES,'UTF-8');}
$action=$_GET['action']??'';$page=$_GET['page']??'register';
if($action==='logout'){unset($_SESSION['lab1406_uid']);header('Location:'.$_SERVER['PHP_SELF']);exit;}
$me=null;
if(!empty($_SESSION['lab1406_uid'])){$st=$db->prepare("SELECT*FROM lab1406_users WHERE id=?");$st->bind_param('i',$_SESSION['lab1406_uid']);$st->execute();$me=$st->get_result()->fetch_assoc();$st->close();}
if($_SERVER['REQUEST_METHOD']==='POST'){
    $raw=file_get_contents('php://input');$ct=$_SERVER['CONTENT_TYPE']??'';
    if(stripos($ct,'xml')!==false||preg_match('/^\s*<[\?a-z]/i',$raw)){
        header('Content-Type:application/json');
        if(function_exists('libxml_disable_entity_loader'))@libxml_disable_entity_loader(false);
        libxml_use_internal_errors(true);$dom=new DOMDocument();$ok=@$dom->loadXML($raw,LIBXML_NOENT|LIBXML_DTDLOAD);libxml_clear_errors();
        if($ok){
            $xp=new DOMXPath($dom);$g=function($t)use($xp){$n=$xp->query('//'.$t);return($n&&$n->length>0)?trim($n->item(0)->textContent):'';};
            $root=$dom->documentElement?$dom->documentElement->nodeName:'';
            if($root==='login'){
                $email=$g('email');$pass=$g('password');
                if($email&&$pass){$st=$db->prepare("SELECT*FROM lab1406_users WHERE email=?");$st->bind_param('s',$email);$st->execute();$user=$st->get_result()->fetch_assoc();$st->close();
                if($user&&password_verify($pass,$user['password'])){$_SESSION['lab1406_uid']=$user['id'];echo json_encode(['status'=>'ok','message'=>'Login successful','redirect'=>$_SERVER['PHP_SELF']]);}
                else echo json_encode(['status'=>'error','message'=>'Authentication failed','detail'=>'No account found for '.esc($email).' or password is incorrect.']);}
                else echo json_encode(['status'=>'error','message'=>'Missing credentials','detail'=>'Email: '.esc($email)]);
            }elseif($root==='register'){
                $name=$g('name');$email=$g('email');$pass=$g('password');$plan=$g('plan')?:'Free';
                if($email){$st=$db->prepare("SELECT id FROM lab1406_users WHERE email=?");$st->bind_param('s',$email);$st->execute();$ex=$st->get_result()->num_rows>0;$st->close();
                if($ex){echo json_encode(['status'=>'error','message'=>'Registration failed','detail'=>'Account with email '.esc($email).' already exists. Name provided: '.esc($name)]);exit;}}
                if($name&&$email&&$pass){$h=password_hash($pass,PASSWORD_BCRYPT);$av=strtoupper(substr($name,0,1).(strpos($name,' ')!==false?substr($name,strpos($name,' ')+1,1):substr($name,1,1)));
                $st=$db->prepare("INSERT INTO lab1406_users(name,email,password,plan,avatar)VALUES(?,?,?,?,?)");$st->bind_param('sssss',$name,$email,$h,$plan,$av);
                if($st->execute())echo json_encode(['status'=>'ok','message'=>'Account created successfully','user'=>['name'=>$name,'email'=>$email,'plan'=>$plan]]);
                else echo json_encode(['status'=>'error','message'=>'Failed','detail'=>'Could not create: '.esc($name)]);$st->close();}
                else echo json_encode(['status'=>'error','message'=>'Missing required fields','detail'=>'Name: '.esc($name).', Email: '.esc($email)]);
            }elseif($root==='vault_item'){
                $site=$g('site');$url=$g('url');$username=$g('username');$password=$g('password');$category=$g('category')?:'Websites';
                if($site&&$url)echo json_encode(['status'=>'ok','message'=>'Item saved to vault','item'=>['site'=>$site,'url'=>$url,'username'=>$username,'category'=>$category]]);
                else echo json_encode(['status'=>'error','message'=>'Could not save item','detail'=>'Site: '.esc($site).', URL: '.esc($url).', Username: '.esc($username)]);
            }elseif($root==='share'){
                $item=$g('item');$recipient=$g('recipient');$permission=$g('permission')?:'read-only';
                echo json_encode(['status'=>'ok','message'=>'Shared successfully','detail'=>'Item "'.esc($item).'" shared with '.esc($recipient).' ('.esc($permission).')']);
            }elseif($root==='settings'){
                $dn=$g('display_name');$em=$g('email');$tz=$g('timezone');$tf=$g('two_factor');
                echo json_encode(['status'=>'ok','message'=>'Settings updated','profile'=>['name'=>$dn,'email'=>$em,'timezone'=>$tz,'two_factor'=>$tf]]);
            }else echo json_encode(['status'=>'error','message'=>'Unknown request type: '.esc($root)]);
        }else{http_response_code(400);echo json_encode(['status'=>'error','message'=>'Invalid request format']);}
        if(function_exists('libxml_disable_entity_loader'))@libxml_disable_entity_loader(true);exit;}}
