<script>function doSave(e){e.preventDefault();var b=document.getElementById('sbtn'),xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<settings>\n  <display_name>'+document.getElementById('s_name').value+'</display_name>\n  <email>'+document.getElementById('s_email').value+'</email>\n  <timezone>'+document.getElementById('s_tz').value+'</timezone>\n  <two_factor>'+(document.getElementById('s_2fa').classList.contains('on')?'enabled':'disabled')+'</two_factor>\n</settings>';b.disabled=true;b.innerHTML='<span class="sp"></span> Saving...';fetch(window.location.pathname,{method:'POST',headers:{'Content-Type':'application/xml'},body:xml}).then(function(r){return r.json()}).then(function(d){b.disabled=false;b.innerHTML='<i class="bi bi-check-lg"></i> Save Changes';var bx=document.getElementById('sres');bx.style.display='block';if(d.status==='ok'){bx.className='rb ok';bx.innerHTML='<i class="bi bi-check-circle me-2"></i>'+H(d.message)+' — '+H(d.profile.name)+' ('+H(d.profile.email)+')';}else{bx.className='rb er';bx.innerHTML='<i class="bi bi-x-circle me-2"></i>'+H(d.detail||d.message);}}).catch(function(){b.disabled=false;b.innerHTML='<i class="bi bi-check-lg"></i> Save Changes';});return false;}function H(s){var d=document.createElement('div');d.appendChild(document.createTextNode(s));return d.innerHTML;}</script></body></html>
