<script>
function openM(t){document.getElementById(t==='add'?'addM':'shM').classList.add('show');}
function closeM(t){var m=document.getElementById(t==='add'?'addM':'shM');m.classList.remove('show');m.querySelector('.rb').style.display='none';}
function openSh(n){document.getElementById('sh_item').value=n;openM('share');}
function addItem(e){e.preventDefault();var b=document.getElementById('abtn'),s=document.getElementById('a_site').value,u=document.getElementById('a_url').value,un=document.getElementById('a_user').value,pw=document.getElementById('a_pass').value,cat=document.getElementById('a_cat').value;var xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<vault_item>\n  <site>'+s+'</site>\n  <url>'+u+'</url>\n  <username>'+un+'</username>\n  <password>'+pw+'</password>\n  <category>'+cat+'</category>\n</vault_item>';b.disabled=true;b.innerHTML='<span class="sp"></span> Saving...';fetch(window.location.pathname,{method:'POST',headers:{'Content-Type':'application/xml'},body:xml}).then(function(r){return r.json()}).then(function(d){b.disabled=false;b.innerHTML='<i class="bi bi-check-lg"></i> Save to Vault';var bx=document.getElementById('ares');bx.style.display='block';if(d.status==='ok'){bx.className='rb ok';bx.innerHTML='<i class="bi bi-check-circle me-2"></i>'+H(d.message)+' — '+H(d.item.site)+' ('+H(d.item.username)+')';var ni=document.getElementById('ni');ni.innerHTML='<div class="pe" style="margin-top:12px"><div class="pr"><div class="ic" style="background:#334155;color:#10b981"><i class="bi bi-globe"></i></div><div><div class="nm">'+H(d.item.site)+'</div><div class="ur">'+H(d.item.url)+'</div></div><div class="us">'+H(d.item.username)+'</div><div class="pw">&#8226;&#8226;&#8226;&#8226;&#8226;&#8226;</div><button class="cp"><i class="bi bi-clipboard"></i> Copy</button><button class="sr" onclick="openSh(\''+H(d.item.site).replace(/'/g,"\\'")+'\')"><i class="bi bi-share"></i> Share</button></div></div>'+ni.innerHTML;document.getElementById('act').innerHTML='<div class="ae"><i class="bi bi-plus-circle"></i> Added <strong style="margin:0 4px">'+H(d.item.site)+'</strong><span class="dt">Just now</span></div>'+document.getElementById('act').innerHTML;}else{bx.className='rb er';bx.innerHTML='<i class="bi bi-x-circle me-2"></i>'+H(d.detail||d.message);}}).catch(function(){b.disabled=false;b.innerHTML='<i class="bi bi-check-lg"></i> Save to Vault';});return false;}
function shareItem(e){e.preventDefault();var b=document.getElementById('shbtn'),item=document.getElementById('sh_item').value,email=document.getElementById('sh_email').value,perm=document.getElementById('sh_perm').value;var xml='<'+'?xml version="1.0" encoding="UTF-8"?'+'>\n<share>\n  <item>'+item+'</item>\n  <recipient>'+email+'</recipient>\n  <permission>'+perm+'</permission>\n</share>';b.disabled=true;b.innerHTML='<span class="sp"></span> Sharing...';fetch(window.location.pathname,{method:'POST',headers:{'Content-Type':'application/xml'},body:xml}).then(function(r){return r.json()}).then(function(d){b.disabled=false;b.innerHTML='<i class="bi bi-send"></i> Share';var bx=document.getElementById('shres');bx.style.display='block';if(d.status==='ok'){bx.className='rb ok';bx.innerHTML='<i class="bi bi-check-circle me-2"></i>'+H(d.detail);document.getElementById('act').innerHTML='<div class="ae"><i class="bi bi-share"></i> Shared <strong style="margin:0 4px">'+H(item)+'</strong> with '+H(email)+'<span class="dt">Just now</span></div>'+document.getElementById('act').innerHTML;}else{bx.className='rb er';bx.innerHTML='<i class="bi bi-x-circle me-2"></i>'+H(d.detail||d.message);}}).catch(function(){b.disabled=false;b.innerHTML='<i class="bi bi-send"></i> Share';});return false;}
function H(s){var d=document.createElement('div');d.appendChild(document.createTextNode(s));return d.innerHTML;}
</script></body></html>
